import numpy as np
from collections import defaultdict
import math

class BM25:
    def __init__(self, k1=1.5, b=0.75):
        self.k1 = k1
        self.b = b
        self.tokenized_docs = []
        self.idf = {}
        self.doc_len = []
        self.avgdl = 0.0
        self.N = 0

    def fit(self, tokenized_docs):
        self.tokenized_docs = tokenized_docs
        self.N = len(tokenized_docs)
        self.doc_len = [len(doc) for doc in tokenized_docs]
        self.avgdl = sum(self.doc_len) / self.N if self.N > 0 else 1.0
        df = defaultdict(int)
        for doc in tokenized_docs:
            for term in set(doc):
                df[term] += 1
        for term, freq in df.items():
            self.idf[term] = math.log((self.N - freq + 0.5) / (freq + 0.5) + 1)
        return self

    def score(self, query_tokens, doc_idx):
        doc = self.tokenized_docs[doc_idx]
        dl = self.doc_len[doc_idx]
        tf_map = defaultdict(int)
        for term in doc:
            tf_map[term] += 1
        total = 0.0
        for term in query_tokens:
            if term not in self.idf:
                continue
            tf = tf_map.get(term, 0)
            numerator = tf * (self.k1 + 1)
            denominator = tf + self.k1 * (1 - self.b + self.b * dl / self.avgdl)
            total += self.idf[term] * numerator / denominator
        return total

    def rank(self, query_tokens, top_k=None):
        scores = [(i, self.score(query_tokens, i)) for i in range(self.N)]
        scores.sort(key=lambda x: x[1], reverse=True)
        if top_k is not None:
            scores = scores[:top_k]
        return [idx for idx, _ in scores]


class DenseRetriever:
    def __init__(self, embed_dim=64):
        self.embed_dim = embed_dim
        self.embeddings = None

    def add_embeddings(self, embeddings):
        self.embeddings = np.array(embeddings)

    def rank(self, query_embedding, top_k=None):
        q = query_embedding / (np.linalg.norm(query_embedding) + 1e-10)
        norms = np.linalg.norm(self.embeddings, axis=1, keepdims=True) + 1e-10
        doc_embs = self.embeddings / norms
        sims = doc_embs @ q
        ranked = np.argsort(sims)[::-1]
        if top_k is not None:
            ranked = ranked[:top_k]
        return ranked.tolist()


def reciprocal_rank_fusion(ranked_lists, k=60):
    scores = defaultdict(float)
    for ranked in ranked_lists:
        for rank, doc_id in enumerate(ranked):
            scores[doc_id] += 1.0 / (k + rank + 1)
    sorted_docs = sorted(scores.items(), key=lambda x: x[1], reverse=True)
    return [doc_id for doc_id, _ in sorted_docs]


def mmr_rerank(candidates, relevance_scores, embeddings, lambda_mmr=0.7, top_k=5):
    if not candidates:
        return []
    top_k = min(top_k, len(candidates))
    selected = []
    remaining = list(candidates)
    rel_map = {idx: score for idx, score in zip(candidates, relevance_scores)}
    emb_map = {idx: embeddings[idx] for idx in candidates}

    def cosine(a, b):
        denom = (np.linalg.norm(a) + 1e-10) * (np.linalg.norm(b) + 1e-10)
        return float(np.dot(a, b) / denom)

    while len(selected) < top_k and remaining:
        if not selected:
            best = max(remaining, key=lambda i: rel_map[i])
        else:
            def mmr_score(i):
                rel = rel_map[i]
                max_sim = max(cosine(emb_map[i], emb_map[s]) for s in selected)
                return lambda_mmr * rel - (1 - lambda_mmr) * max_sim
            best = max(remaining, key=mmr_score)
        selected.append(best)
        remaining.remove(best)
    return selected


class RAGRetriever:
    def __init__(self, embed_dim=64):
        self.embed_dim = embed_dim
        self.docs = []
        self.embeddings = []
        self.bm25 = BM25()
        self.dense = DenseRetriever(embed_dim)

    def _tokenize(self, text):
        return text.lower().split()

    def _embed(self, text, seed=None):
        if seed is None:
            seed = hash(text) % (2**31)
        rng = np.random.RandomState(seed)
        v = rng.randn(self.embed_dim)
        return v / (np.linalg.norm(v) + 1e-10)

    def add_documents(self, docs):
        self.docs = docs
        tokenized = [self._tokenize(d) for d in docs]
        self.bm25.fit(tokenized)
        self.embeddings = [self._embed(d, seed=i) for i, d in enumerate(docs)]
        self.dense.add_embeddings(self.embeddings)

    def query(self, q, top_k=5, lambda_mmr=0.7):
        tokens = self._tokenize(q)
        q_emb = self._embed(q)
        n = len(self.docs)
        fetch_k = min(n, max(top_k * 3, 20))
        bm25_ranking = self.bm25.rank(tokens, top_k=fetch_k)
        dense_ranking = self.dense.rank(q_emb, top_k=fetch_k)
        fused = reciprocal_rank_fusion([bm25_ranking, dense_ranking])
        candidates = fused[:fetch_k]
        rel_scores = [1.0 / (rank + 1) for rank in range(len(candidates))]
        emb_array = np.array(self.embeddings)
        result = mmr_rerank(candidates, rel_scores, emb_array, lambda_mmr, top_k)
        return result
